contracts/libraries/OSLOConstants.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title OSLOConstants
/// @notice All hardcoded protocol constants for the OSLO Protocol V2
/// @dev USDT-based staking, 4-tier ranged yields, lifetime 0.45% rate, combined 3X cap
library OSLOConstants {
    // ─── Token Supply ───────────────────────────────────────────────────
    uint256 public constant TOTAL_SUPPLY = 11_100_000 * 1e18;       // 11.1M total
    uint256 public constant CONTRACT_RESERVE = 11_000_000 * 1e18;   // 11M held by InvestmentEngine
    uint256 public constant DEX_ALLOCATION = 100_000 * 1e18;        // 100K seeded to OSLODEX with USDT pair

    // ─── Basis Points (10000 = 100%) ────────────────────────────────────
    uint256 public constant BASIS_POINTS = 10_000;

    // ─── Withdrawal Fees ────────────────────────────────────────────────
    uint256 public constant WITHDRAWAL_FEE_BP = 1_000; // 10% on profit claims

    // ─── Minimum Withdrawal Threshold ───────────────────────────────────
    uint256 public constant MIN_WITHDRAWAL_THRESHOLD = 10 * 1e18; // $10 USDT minimum to withdraw

    // ─── Sell Tax ───────────────────────────────────────────────────────
    // On every sell/swap, tokens are distributed:
    //   10% fee → burned (the fee is paid by burning tokens)
    //   70% → InvestmentEngine (contract reserve for rewards)
    //   20% → additionally burned (deflationary)
    //   Total burn per sell = 30% (until burn cap is reached)
    //   USDT from the swap stays in the DEX as liquidity.
    uint256 public constant SELL_TAX_BP = 1_000;         // 10% sell tax (burned as fee)
    uint256 public constant SELL_TAX_TO_CONTRACT_BP = 7_000; // 70% → InvestmentEngine (contract reserve)
    uint256 public constant SELL_TAX_TO_BURN_BP = 2_000;     // 20% additional burn
    uint256 public constant SELL_TAX_FEE_BURN_BP = 1_000;    // 10% fee → burned (was LP, now burn)

    // ─── 3X Return Cap ──────────────────────────────────────────────────
    uint256 public constant RETURN_CAP_MULTIPLIER = 3; // 3X combined cap on all earnings

    // ─── Treasury Distribution ──────────────────────────────────────────
    uint256 public constant TREASURY_TO_RANK_BP = 0;      // 0% → (paid from Liquidity)
    uint256 public constant TREASURY_TO_DAO_BP = 0;       // 0% → (paid from Liquidity)
    uint256 public constant TREASURY_TO_LP_BP = 10_000;   // 100% → liquidity

    // ─── Referral Commissions (basis points on profit portion) ──────────
    uint256 public constant MAX_REFERRAL_LEVELS = 20;
    uint256 public constant QUALIFIED_DIRECT_MIN_DEPOSIT = 100 * 1e18; // $100 USDT

    // ─── DAO ────────────────────────────────────────────────────────────
    uint256 public constant MAX_DAO_MEMBERS = 200;
    uint256 public constant DAO_TEAM_SIZE_REQUIREMENT = 250;
    uint256 public constant DAO_MONTHLY_ROYALTY_BP = 50; // 0.5% monthly royalty

    // ─── Governance ─────────────────────────────────────────────────────
    uint256 public constant PROPOSAL_THRESHOLD_BP = 100;     // 1% of supply
    uint256 public constant VOTING_PERIOD_BLOCKS = 86_400;   // ~3 days at 3s blocks
    uint256 public constant TIMELOCK_DELAY = 48 hours;

    // ─── Week Duration ──────────────────────────────────────────────────
    uint256 public constant WEEK_DURATION = 7 days;

    // ─── Dead Address ───────────────────────────────────────────────────
    address public constant DEAD_ADDRESS = 0x000000000000000000000000000000000000dEaD;

    // ─── Burn Cap ───────────────────────────────────────────────────────
    uint256 public constant MAX_BURN_SUPPLY = 9_990_000 * 1e18;   // 90% of 11.1M — stop burning when this much is burned
    uint256 public constant MIN_REMAINING_SUPPLY = 1_110_000 * 1e18; // 10% of 11.1M — minimum tokens remaining after burn

    // ─── Early Exit Period ───────────────────────────────────────────────
    uint256 public constant EARLY_EXIT_PERIOD = 10 days;           // 10-day early exit window
    uint256 public constant EARLY_EXIT_FEE_BP = 1_000;             // 10% early exit fee

    // ─── Investment Tier Boundaries (in USDT, 18 decimals) ──────────────
    uint256 public constant MAX_DEPOSIT_PER_TX = 5_000 * 1e18; // $5,000 max per single deposit
    uint256 public constant TIER1_MIN = 10 * 1e18;
    uint256 public constant TIER1_MAX = 499 * 1e18;
    uint256 public constant TIER2_MIN = 500 * 1e18;
    uint256 public constant TIER2_MAX = 2_499 * 1e18;
    uint256 public constant TIER3_MIN = 2_500 * 1e18;
    uint256 public constant TIER3_MAX = 4_999 * 1e18;
    uint256 public constant TIER4_MIN = 5_000 * 1e18;
    uint256 public constant TIER4_IMPLICIT_MAX = 50_000 * 1e18; // For rate interpolation cap

    // ─── Daily Return Rates (basis points, ranged per tier) ─────────────
    // Tier 1: $10–$499  →  0.50%–1.00% daily
    uint256 public constant TIER1_RATE_MIN = 50;   // 0.50%
    uint256 public constant TIER1_RATE_MAX = 100;  // 1.00%
    // Tier 2: $500–$2,499 → 0.75%–1.15% daily
    uint256 public constant TIER2_RATE_MIN = 75;   // 0.75%
    uint256 public constant TIER2_RATE_MAX = 115;  // 1.15%
    // Tier 3: $2,500–$4,999 → 1.00%–1.50% daily
    uint256 public constant TIER3_RATE_MIN = 100;  // 1.00%
    uint256 public constant TIER3_RATE_MAX = 150;  // 1.50%
    // Tier 4: $5,000+       → 1.00%–1.75% daily
    uint256 public constant TIER4_RATE_MIN = 100;  // 1.00%
    uint256 public constant TIER4_RATE_MAX = 175;  // 1.75%

    // ─── Lifetime Rate (after 3 months, applies to ALL stakes) ───────────
    uint256 public constant LIFETIME_RATE = 45;           // 0.45% daily
    uint256 public constant LIFETIME_RATE_START = 90 days; // 3 months after launch

    // ─── Launch Timestamp ───────────────────────────────────────────────
    // Same as V1: May 10, 2026 00:00:00 UTC
    uint256 public constant LAUNCH_TIMESTAMP = 1_778_371_200;

    // ─── Referral Commission Rates (basis points) ───────────────────────
    uint256 public constant REFERRAL_L1_BP = 3_000;   // 30%   (level 1)
    uint256 public constant REFERRAL_L2_BP = 2_000;   // 20%   (level 2)
    uint256 public constant REFERRAL_L3_10_BP = 100;   // 1.00% (levels 3–10)
    uint256 public constant REFERRAL_L11_15_BP = 50;   // 0.50% (levels 11–15)
    uint256 public constant REFERRAL_L16_20_BP = 25;   // 0.25% (levels 16–20)

    // ─── Rank Turnover Thresholds (in USDT, 18 decimals) ────────────────
    uint256 public constant RANK1_TURNOVER = 10_000 * 1e18;
    uint256 public constant RANK2_TURNOVER = 25_000 * 1e18;
    uint256 public constant RANK3_TURNOVER = 75_000 * 1e18;
    uint256 public constant RANK4_TURNOVER = 200_000 * 1e18;
    uint256 public constant RANK5_TURNOVER = 500_000 * 1e18;
    uint256 public constant RANK6_TURNOVER = 1_200_000 * 1e18;
    uint256 public constant RANK7_TURNOVER = 2_500_000 * 1e18;

    // ─── Rank Bonus Percentages (basis points) ──────────────────────────
    uint256 public constant RANK1_BONUS_BP = 100; // 1.00% (Bronze)
    uint256 public constant RANK2_BONUS_BP = 50;  // 0.50% (Silver)
    uint256 public constant RANK3_BONUS_BP = 30;  // 0.30% (Gold)
    uint256 public constant RANK4_BONUS_BP = 20;  // 0.20% (Platinum)
    uint256 public constant RANK5_BONUS_BP = 15;  // 0.15% (Diamond)
    uint256 public constant RANK6_BONUS_BP = 10;  // 0.10% (Master)
    uint256 public constant RANK7_BONUS_BP = 5;   // 0.05% (Grandmaster)

    // ─── Rank Leg Ratio Qualification (basis points) ────────────────────
    uint256 public constant RANK_MAIN_LEG_MAX_BP = 4_000;  // 40% — main leg cap
    uint256 public constant RANK_OTHER_LEGS_MIN_BP = 6_000; // 60% — other legs minimum
}

contracts/OSLORankSystem.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./libraries/OSLOConstants.sol";
import "./interfaces/IRankSystem.sol";
import "./interfaces/IReferral.sol";
import "./interfaces/IInvestmentEngine.sol";

/// @title OSLORankSystem
/// @notice Calculates weekly team turnover and distributes progressive rank bonuses in USDT.
/// @dev V2: Bonuses paid in USDT. Notifies InvestmentEngine for combined 3X cap tracking.
contract OSLORankSystem is IRankSystem, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ─── State ──────────────────────────────────────────────────────────

    IERC20 public immutable usdt;
    address public investmentEngine;
    address public referral;
    address public admin;
    address public timelock;
    bool public setupComplete;

    /// @notice Weekly turnover per user per weekId: weeklyTurnover[user][weekId]
    mapping(address => mapping(uint256 => uint256)) public weeklyTurnoverData;

    /// @notice Per-leg weekly turnover: legTurnover[user][weekId][legAddress]
    mapping(address => mapping(uint256 => mapping(address => uint256))) public legTurnover;

    /// @notice Whether a user has claimed their bonus for a given week
    mapping(address => mapping(uint256 => bool)) public weekBonusClaimed;

    /// @notice Rank bonus pool balance available for distribution
    uint256 public bonusPoolBalance;

    /// @notice Total bonuses distributed all-time (USDT)
    uint256 public totalBonusesDistributed;

    /// @notice Genesis timestamp for week epoch calculation (set to first Monday UTC)
    uint256 public immutable genesisTimestamp;

    // ─── Events ─────────────────────────────────────────────────────────
    event RankAchieved(address indexed user, uint256 rank, uint256 weekId, uint256 turnover);
    event RankBonusClaimed(address indexed user, uint256 amount, uint256 weekId);
    event BonusPoolFunded(uint256 amount);
    event TurnoverRecorded(address indexed user, uint256 amount, uint256 weekId);

    // ─── Errors ─────────────────────────────────────────────────────────
    error OnlyAdmin();
    error OnlyTimelock();
    error SetupAlreadyComplete();
    error AlreadyClaimed();
    error NoBonus();
    error InsufficientBonusPool();
    error CurrentWeekNotClaimable();
    error ZeroAddress();

    modifier onlyAdmin() {
        if (msg.sender != admin) revert OnlyAdmin();
        _;
    }

    modifier onlyTimelock() {
        if (msg.sender != timelock) revert OnlyTimelock();
        _;
    }

    constructor(address _usdt) {
        if (_usdt == address(0)) revert ZeroAddress();
        usdt = IERC20(_usdt);
        admin = msg.sender;
        // Set genesis to a fixed Monday 00:00 UTC (Jan 1, 2024 was a Monday)
        genesisTimestamp = 1704067200; // 2024-01-01 00:00:00 UTC (Monday)
    }

    // ─── Setup ──────────────────────────────────────────────────────────

    function configure(address _investmentEngine, address _referral, address _timelock) external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        investmentEngine = _investmentEngine;
        referral = _referral;
        timelock = _timelock;
    }

    function completeSetup() external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        setupComplete = true;
        admin = address(0);
    }

    /// @notice Update the InvestmentEngine address. Only callable by Timelock after setup.
    /// @dev Used when redeploying InvestmentEngine with new features.
    function setInvestmentEngine(address _investmentEngine) external onlyTimelock {
        investmentEngine = _investmentEngine;
    }

    // ─── Core Functions ─────────────────────────────────────────────────

    /// @notice Record turnover for a user in the current week. Called by InvestmentEngine.
    /// @param leg The direct child address identifying which referral leg this turnover belongs to
    function recordTurnover(address user, address leg, uint256 amount) external override {
        uint256 weekId = getCurrentWeekId();
        weeklyTurnoverData[user][weekId] += amount;
        legTurnover[user][weekId][leg] += amount;
        emit TurnoverRecorded(user, amount, weekId);
    }

    /// @notice Receive USDT into the bonus pool from Treasury
    function receiveBonusPool(uint256 amount) external override {
        usdt.safeTransferFrom(msg.sender, address(this), amount);
        bonusPoolBalance += amount;
        emit BonusPoolFunded(amount);
    }

    /// @notice Claim rank bonus for a completed week. Paid in USDT.
    /// @dev Can only claim for past weeks, not the current one. Requires 40/60 leg ratio qualification.
    function claimRankBonus() external override nonReentrant {
        uint256 currentWeek = getCurrentWeekId();
        // Claim for the most recent completed week
        uint256 claimWeek = currentWeek - 1;
        if (claimWeek == 0) revert NoBonus();

        if (weekBonusClaimed[msg.sender][claimWeek]) revert AlreadyClaimed();

        // Must satisfy 40/60 leg ratio to qualify
        if (!_isRankQualified(msg.sender, claimWeek)) revert NoBonus();

        uint256 turnover = weeklyTurnoverData[msg.sender][claimWeek];
        uint256 rank = _getRankFromTurnover(turnover);
        if (rank == 0) revert NoBonus();

        uint256 bonusBP = _getRankBonusBP(rank);
        uint256 bonus = (turnover * bonusBP) / OSLOConstants.BASIS_POINTS;

        if (bonus == 0) revert NoBonus();
        if (bonus > bonusPoolBalance) revert InsufficientBonusPool();

        weekBonusClaimed[msg.sender][claimWeek] = true;
        bonusPoolBalance -= bonus;
        totalBonusesDistributed += bonus;

        // Pay bonus in USDT
        usdt.safeTransfer(msg.sender, bonus);

        // Notify InvestmentEngine for combined 3X cap tracking
        if (investmentEngine != address(0)) {
            IInvestmentEngine(investmentEngine).notifyRankBonus(msg.sender, bonus);
        }

        emit RankAchieved(msg.sender, rank, claimWeek, turnover);
        emit RankBonusClaimed(msg.sender, bonus, claimWeek);
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function getCurrentWeekId() public view override returns (uint256) {
        return (block.timestamp - genesisTimestamp) / OSLOConstants.WEEK_DURATION + 1;
    }

    function getCurrentRank(address user) external view override returns (uint256) {
        uint256 weekId = getCurrentWeekId();
        if (!_isRankQualified(user, weekId)) return 0;
        uint256 turnover = weeklyTurnoverData[user][weekId];
        return _getRankFromTurnover(turnover);
    }

    function getWeeklyTurnover(address user, uint256 weekId) external view override returns (uint256) {
        return weeklyTurnoverData[user][weekId];
    }

    function getLegTurnover(address user, uint256 weekId, address leg) external view override returns (uint256) {
        return legTurnover[user][weekId][leg];
    }

    function isRankQualified(address user) external view override returns (bool) {
        uint256 weekId = getCurrentWeekId();
        return _isRankQualified(user, weekId);
    }

    function getPendingBonus(address user) external view returns (uint256) {
        uint256 currentWeek = getCurrentWeekId();
        if (currentWeek <= 1) return 0;
        uint256 claimWeek = currentWeek - 1;
        if (weekBonusClaimed[user][claimWeek]) return 0;

        if (!_isRankQualified(user, claimWeek)) return 0;

        uint256 turnover = weeklyTurnoverData[user][claimWeek];
        uint256 rank = _getRankFromTurnover(turnover);
        if (rank == 0) return 0;

        uint256 bonusBP = _getRankBonusBP(rank);
        return (turnover * bonusBP) / OSLOConstants.BASIS_POINTS;
    }

    // ─── Internal Functions ─────────────────────────────────────────────

    /// @dev Check 40/60 leg ratio: main leg <= 40% of total, other legs >= 60% of total
    function _isRankQualified(address user, uint256 weekId) internal view returns (bool) {
        uint256 totalTurnover = weeklyTurnoverData[user][weekId];
        if (totalTurnover == 0) return false;

        if (referral == address(0)) return true; // No referral set — skip check during setup
        address[] memory directs = IReferral(referral).getDirectReferrals(user);
        if (directs.length == 0) return false;

        uint256 maxLegTurnover = 0;
        for (uint256 i = 0; i < directs.length; i++) {
            uint256 legT = legTurnover[user][weekId][directs[i]];
            if (legT > maxLegTurnover) maxLegTurnover = legT;
        }

        return maxLegTurnover * OSLOConstants.BASIS_POINTS <= totalTurnover * OSLOConstants.RANK_MAIN_LEG_MAX_BP;
    }

    /// @dev Progressive ranking — returns highest rank achieved (1-7, 0 for none)
    function _getRankFromTurnover(uint256 turnover) internal pure returns (uint256) {
        if (turnover >= OSLOConstants.RANK7_TURNOVER) return 7;
        if (turnover >= OSLOConstants.RANK6_TURNOVER) return 6;
        if (turnover >= OSLOConstants.RANK5_TURNOVER) return 5;
        if (turnover >= OSLOConstants.RANK4_TURNOVER) return 4;
        if (turnover >= OSLOConstants.RANK3_TURNOVER) return 3;
        if (turnover >= OSLOConstants.RANK2_TURNOVER) return 2;
        if (turnover >= OSLOConstants.RANK1_TURNOVER) return 1;
        return 0;
    }

    /// @dev Get bonus basis points for a rank (progressive, not cumulative)
    function _getRankBonusBP(uint256 rank) internal pure returns (uint256) {
        if (rank == 7) return OSLOConstants.RANK7_BONUS_BP;
        if (rank == 6) return OSLOConstants.RANK6_BONUS_BP;
        if (rank == 5) return OSLOConstants.RANK5_BONUS_BP;
        if (rank == 4) return OSLOConstants.RANK4_BONUS_BP;
        if (rank == 3) return OSLOConstants.RANK3_BONUS_BP;
        if (rank == 2) return OSLOConstants.RANK2_BONUS_BP;
        if (rank == 1) return OSLOConstants.RANK1_BONUS_BP;
        return 0;
    }
}

contracts/OSLOReferral.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./libraries/OSLOConstants.sol";
import "./interfaces/IReferral.sol";
import "./interfaces/IInvestmentEngine.sol";
import "./interfaces/IOSLODEX.sol";

/// @title OSLOReferral
/// @notice Decentralized 20-level referral tree with level unlocking and USDT commission distribution.
/// @dev V2: $1 USDT registration fee → routed to DEX as liquidity. OSLO received is burned.
contract OSLOReferral is IReferral, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ─── Structs ────────────────────────────────────────────────────────

    struct UserReferralInfo {
        address referrer;
        address[] directReferrals;
        uint256 unlockedLevels;
        uint256 totalEarned;        // Total USDT-equivalent commissions earned
        bool registered;
    }

    // ─── State ──────────────────────────────────────────────────────────

    IERC20 public immutable usdt;
    IERC20 public immutable osloToken;
    address public investmentEngine;
    address public osloDex;
    address public admin;
    address public timelock;
    bool public setupComplete;

    uint256 public constant REGISTRATION_FEE = 1 * 1e18; // $1 USDT

    mapping(address => UserReferralInfo) public userInfo;
    mapping(address => uint256) public referralRewards;    // USDT-denominated pending commissions
    mapping(address => mapping(uint256 => uint256)) public levelIncome; // Per-level income (USDT-denominated)
    uint256 public totalRegistered;
    uint256 public totalCommissionsPaid;
    uint256 public totalFeesCollected; // Total registration fees collected

    // ─── Events ─────────────────────────────────────────────────────────
    event UserRegistered(address indexed user, address indexed referrer);
    event LevelUnlocked(address indexed user, uint256 level);
    event ReferralPaid(address indexed upline, address indexed downline, uint256 level, uint256 amount);
    event ReferralRewardsClaimed(address indexed user, uint256 amount);
    event RegistrationFeeProcessed(address indexed user, uint256 fee, uint256 osloBurned);

    // ─── Errors ─────────────────────────────────────────────────────────
    error OnlyAdmin();
    error OnlyInvestmentEngine();
    error OnlyTimelock();
    error SetupAlreadyComplete();
    error AlreadyRegistered();
    error InvalidReferrer();
    error NotRegistered();
    error NothingToClaim();
    error SelfReferral();
    error ZeroAddress();

    modifier onlyAdmin() {
        if (msg.sender != admin) revert OnlyAdmin();
        _;
    }

    modifier onlyInvestmentEngine() {
        if (msg.sender != investmentEngine) revert OnlyInvestmentEngine();
        _;
    }

    modifier onlyTimelock() {
        if (msg.sender != timelock) revert OnlyTimelock();
        _;
    }

    constructor(address _usdt, address _osloToken) {
        if (_usdt == address(0) || _osloToken == address(0)) revert ZeroAddress();
        usdt = IERC20(_usdt);
        osloToken = IERC20(_osloToken);
        admin = msg.sender;
    }

    // ─── Setup ──────────────────────────────────────────────────────────

    function configure(
        address _investmentEngine,
        address _osloDex,
        address _timelock
    ) external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        investmentEngine = _investmentEngine;
        osloDex = _osloDex;
        timelock = _timelock;
    }

    function completeSetup() external onlyAdmin {
        if (setupComplete) revert SetupAlreadyComplete();
        setupComplete = true;
        admin = address(0);
    }

    // ─── Registration ($1 USDT Fee) ─────────────────────────────────────

    /// @notice Register a new user with a referrer. $1 USDT fee → DEX liquidity + OSLO burn.
    /// @dev $1 USDT is swapped for OSLO on DEX, then OSLO is permanently burned.
    function register(address user, address referrer) external override {
        if (user == address(0)) revert ZeroAddress();
        if (userInfo[user].registered) revert AlreadyRegistered();
        if (user == referrer) revert SelfReferral();
        if (referrer != address(0) && !userInfo[referrer].registered) revert InvalidReferrer();

        // Charge $1 USDT registration fee
        usdt.safeTransferFrom(user, address(this), REGISTRATION_FEE);
        totalFeesCollected += REGISTRATION_FEE;

        // Route fee to DEX as liquidity: swap USDT for OSLO, then burn OSLO
        if (osloDex != address(0)) {
            usdt.forceApprove(osloDex, REGISTRATION_FEE);
            try IOSLODEX(osloDex).swapUSDTForOSLO(REGISTRATION_FEE, 0) returns (uint256 osloReceived) {
                if (osloReceived > 0) {
                    osloToken.safeTransfer(OSLOConstants.DEAD_ADDRESS, osloReceived);
                    emit RegistrationFeeProcessed(user, REGISTRATION_FEE, osloReceived);
                }
            } catch {
                // If DEX swap fails (e.g. no reserves yet), USDT stays in contract
                // Can be recovered by admin before completeSetup
            }
        }

        userInfo[user].registered = true;
        userInfo[user].referrer = referrer;
        userInfo[user].unlockedLevels = 0;

        if (referrer != address(0)) {
            userInfo[referrer].directReferrals.push(user);
        }

        totalRegistered++;

        emit UserRegistered(user, referrer);
    }

    // ─── Level Unlocking ────────────────────────────────────────────────

    /// @notice Check and auto-unlock levels based on qualified direct referrals
    function checkAndUnlockLevels(address user) external override {
        if (!userInfo[user].registered) return;

        uint256 qualifiedDirects = _countQualifiedDirects(user);
        uint256 newLevel = _getMaxUnlockedLevel(qualifiedDirects);

        if (newLevel > userInfo[user].unlockedLevels) {
            uint256 oldLevel = userInfo[user].unlockedLevels;
            userInfo[user].unlockedLevels = newLevel;
            for (uint256 i = oldLevel + 1; i <= newLevel; i++) {
                emit LevelUnlocked(user, i);
            }
        }
    }

    // ─── Commission Distribution ────────────────────────────────────────

    /// @notice Distribute referral commissions on the profit portion of downline earnings.
    /// @dev Called by InvestmentEngine on each claim. Commissions accrue in USDT.
    /// @param user The user whose earnings generated the commission
    /// @param profitAmount The profit portion of the user's claim (USDT-denominated)
    function distributeReferralCommission(address user, uint256 profitAmount) external override {
        if (profitAmount == 0) return;

        address current = user;
        for (uint256 level = 1; level <= OSLOConstants.MAX_REFERRAL_LEVELS; level++) {
            address upline = userInfo[current].referrer;
            if (upline == address(0)) break;

            // Check if upline has this level unlocked
            if (userInfo[upline].unlockedLevels >= level) {
                uint256 commissionRate = _getCommissionRate(level);
                uint256 commission = (profitAmount * commissionRate) / OSLOConstants.BASIS_POINTS;

                if (commission > 0) {
                    referralRewards[upline] += commission;
                    levelIncome[upline][level] += commission;
                    userInfo[upline].totalEarned += commission;
                    totalCommissionsPaid += commission;

                    // Notify InvestmentEngine for combined 3X cap tracking
                    if (investmentEngine != address(0)) {
                        IInvestmentEngine(investmentEngine).notifyLevelIncome(upline, commission);
                    }

                    emit ReferralPaid(upline, user, level, commission);
                }
            }

            current = upline;
        }
    }

    /// @notice Claim accumulated referral rewards. Paid in USDT from contract balance.
    function claimReferralRewards() external override nonReentrant {
        uint256 amount = referralRewards[msg.sender];
        if (amount == 0) revert NothingToClaim();

        referralRewards[msg.sender] = 0;

        // Pay commission in USDT
        usdt.safeTransfer(msg.sender, amount);

        emit ReferralRewardsClaimed(msg.sender, amount);
    }

    /// @notice Update the InvestmentEngine address. Only callable by Timelock after setup.
    /// @dev Used when redeploying InvestmentEngine with new features.
    function setInvestmentEngine(address _investmentEngine) external onlyTimelock {
        investmentEngine = _investmentEngine;
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function isRegistered(address user) external view override returns (bool) {
        return userInfo[user].registered;
    }

    function getReferrer(address user) external view override returns (address) {
        return userInfo[user].referrer;
    }

    function getDirectReferrals(address user) external view override returns (address[] memory) {
        return userInfo[user].directReferrals;
    }

    function getQualifiedDirectsCount(address user) external view override returns (uint256) {
        return _countQualifiedDirects(user);
    }

    function getUnlockedLevels(address user) external view override returns (uint256) {
        return userInfo[user].unlockedLevels;
    }

    function getTeamSize(address user) external view override returns (uint256) {
        return _getTeamSize(user, 0);
    }

    /// @notice Get level income earned at a specific level (USDT-denominated)
    function getLevelIncome(address user, uint256 level) external view returns (uint256) {
        return levelIncome[user][level];
    }

    /// @notice Get total and per-level income for all 20 levels (index 0 = total)
    /// @return Array of [total, L1, L2, ..., L20] (21 elements)
    function getAllLevelIncome(address user) external view returns (uint256[21] memory) {
        uint256[21] memory result;
        for (uint256 i = 1; i <= OSLOConstants.MAX_REFERRAL_LEVELS; i++) {
            result[i] = levelIncome[user][i];
            result[0] += result[i];
        }
        return result;
    }

    // ─── Internal Functions ─────────────────────────────────────────────

    /// @dev Count direct referrals with >= $100 active deposit
    function _countQualifiedDirects(address user) internal view returns (uint256) {
        uint256 count = 0;
        address[] storage directs = userInfo[user].directReferrals;
        for (uint256 i = 0; i < directs.length; i++) {
            if (investmentEngine != address(0)) {
                uint256 activeDeposit = IInvestmentEngine(investmentEngine).getActiveDeposit(directs[i]);
                if (activeDeposit >= OSLOConstants.QUALIFIED_DIRECT_MIN_DEPOSIT) {
                    count++;
                }
            }
        }
        return count;
    }

    /// @dev Get maximum unlocked level based on qualified directs count
    function _getMaxUnlockedLevel(uint256 qualifiedDirects) internal pure returns (uint256) {
        if (qualifiedDirects >= 7) return 20;
        if (qualifiedDirects >= 5) return 16;
        if (qualifiedDirects >= 3) return 12;
        if (qualifiedDirects >= 2) return 8;
        if (qualifiedDirects >= 1) return 3;
        return 0;
    }

    /// @dev Get commission rate for a specific level
    function _getCommissionRate(uint256 level) internal pure returns (uint256) {
        if (level == 1) return OSLOConstants.REFERRAL_L1_BP;
        if (level == 2) return OSLOConstants.REFERRAL_L2_BP;
        if (level >= 3 && level <= 10) return OSLOConstants.REFERRAL_L3_10_BP;
        if (level >= 11 && level <= 15) return OSLOConstants.REFERRAL_L11_15_BP;
        if (level >= 16 && level <= 20) return OSLOConstants.REFERRAL_L16_20_BP;
        return 0;
    }

    /// @dev Recursively count team size across 20 levels
    function _getTeamSize(address user, uint256 depth) internal view returns (uint256) {
        if (depth >= OSLOConstants.MAX_REFERRAL_LEVELS) return 0;

        address[] storage directs = userInfo[user].directReferrals;
        uint256 size = directs.length;
        for (uint256 i = 0; i < directs.length; i++) {
            size += _getTeamSize(directs[i], depth + 1);
        }
        return size;
    }
}

